{
  description = "Flux - PWA workout tracker";

  inputs = {
    nixpkgs.url = "github:NixOS/nixpkgs/nixos-unstable";
    flake-utils.url = "github:numtide/flake-utils";
    klaus = {
      url = "github:patflynn/klaus";
      inputs.nixpkgs.follows = "nixpkgs";
    };
  };

  outputs =
    {
      self,
      nixpkgs,
      flake-utils,
      klaus,
    }:
    flake-utils.lib.eachDefaultSystem (
      system:
      let
        pkgs = nixpkgs.legacyPackages.${system};
      in
      {
        devShells.default = pkgs.mkShell {
          buildInputs = with pkgs; [
            nodejs_20
            nodePackages.serve
            imagemagick
            nixfmt-rfc-style
            klaus.packages.${system}.default
          ];

          shellHook = ''
            echo "Flux dev shell"
            echo "Commands:"
            echo "  serve .             - Start local server"
            echo "  node tests/validate.js  - Run validation"
          '';
        };

        # Separate shell for E2E tests with Playwright
        devShells.test = pkgs.mkShell {
          buildInputs = with pkgs; [
            nodejs_20
            nodePackages.serve
            playwright-driver.browsers
          ];

          shellHook = ''
            export PLAYWRIGHT_BROWSERS_PATH=${pkgs.playwright-driver.browsers}
            export PLAYWRIGHT_SKIP_BROWSER_DOWNLOAD=1
            npm install --prefer-offline --no-audit --no-fund --quiet
            echo "Flux test shell (with Playwright)"
          '';
        };

        packages.default = pkgs.stdenv.mkDerivation {
          pname = "flux";
          version = "1.0.0";
          src = ./.;

          installPhase =
            let
              commit = self.shortRev or "dev";
            in
            ''
              mkdir -p $out
              for f in index.html style.css app.js timer.js manifest.json; do
                cp $f $out/
              done
              cp -r data $out/
              echo '{"version":"${version}","commit":"${commit}"}' > $out/version.json
            '';
        };
      }
    );
}

